-- db/seed.sql
-- Auto-generated sample data for SteelWorks Unified Operational Summary
BEGIN;

WITH production_batch AS (
  VALUES ('production','Ops_Production_Log.xlsx','Production Log','seed.sql', NULL)
  RETURNING import_batch_id
), shipping_batch AS (
  VALUES ('shipping','Ops_Shipping_Log.xlsx','Shipping Log','seed.sql', NULL)
  RETURNING import_batch_id
), inspection_batch AS (
  VALUES ('inspection','(synthetic)','Inspection Log','seed.sql', NULL)
  RETURNING import_batch_id
)
SELECT 1;

-- Lots (canonical business key lot_code)

-- Production records (from Ops_Production_Log.xlsx)

-- Shipping records (from Ops_Shipping_Log.xlsx)

-- Defect types (reference data)

-- Inspection records (synthetic to support defect drill-down demos)

-- Defect observations (synthetic)

-- Import rejects (examples for AC3: rows that fail alignment / validation)
VALUES (
  (SELECT import_batch_id FROM ops.import_batches WHERE source_system='production' ORDER BY import_batch_id DESC LIMIT 1),
  'production', 999, 'missing production_date', '{"Lot ID":"LOT-20260199-999","Date":null}'::jsonb
) ON CONFLICT DO NOTHING;

-- Operational summaries (ETL / reconciliation materialization)
WITH pr_base AS (
  SELECT pr.* FROM ops.production_records pr
), insp_agg AS (
  SELECT
    ir.inspection_record_id, ir.lot_id, ir.inspection_date,
    SUM(do.qty_defects) AS total_defects,
    (SELECT dt.defect_code
     FROM ops.defect_observations do2
     JOIN ops.defect_types dt ON dt.defect_type_id = do2.defect_type_id
     WHERE do2.inspection_record_id = ir.inspection_record_id
     ORDER BY do2.qty_defects DESC, dt.defect_code ASC
     LIMIT 1) AS top_defect_code
  FROM ops.inspection_records ir
  LEFT JOIN ops.defect_observations do ON do.inspection_record_id = ir.inspection_record_id
  GROUP BY ir.inspection_record_id, ir.lot_id, ir.inspection_date
)
  lot_id, record_date,
  production_record_id, production_line, part_number, units_planned, units_actual, downtime_minutes, line_issue_flag, primary_issue,
  inspection_record_id, total_defects, top_defect_code,
  shipping_record_id, ship_status, ship_date, qty_shipped,
  reconciliation_status, missing_production, missing_inspection, missing_shipping, incomplete_reason
)
SELECT
  pr.lot_id, pr.production_date AS record_date,
  pr.production_record_id, pr.production_line, pr.part_number, pr.units_planned, pr.units_actual, pr.downtime_minutes, pr.line_issue_flag, pr.primary_issue,
  ia.inspection_record_id, ia.total_defects, ia.top_defect_code,
  sr.shipping_record_id, COALESCE(sr.ship_status,'unknown') AS ship_status, sr.ship_date, sr.qty_shipped,
  CASE
    WHEN pr.production_date IS NULL THEN 'insufficient_data'
    WHEN sr.shipping_record_id IS NULL OR ia.inspection_record_id IS NULL THEN 'missing_sources'
    ELSE 'reconciled'
  END AS reconciliation_status,
  FALSE AS missing_production,
  (ia.inspection_record_id IS NULL) AS missing_inspection,
  (sr.shipping_record_id IS NULL) AS missing_shipping,
  CASE
    WHEN pr.production_date IS NULL THEN 'missing production_date'
    WHEN sr.shipping_record_id IS NULL AND ia.inspection_record_id IS NULL THEN 'missing inspection and shipping'
    WHEN sr.shipping_record_id IS NULL THEN 'missing shipping'
    WHEN ia.inspection_record_id IS NULL THEN 'missing inspection'
    ELSE NULL
  END AS incomplete_reason
FROM pr_base pr
-- Match inspection by (lot_id, production_date)
LEFT JOIN insp_agg ia ON ia.lot_id = pr.lot_id AND ia.inspection_date = pr.production_date
-- Pick the closest ship record on/after production_date (within 21 days)
LEFT JOIN LATERAL (
  SELECT sr.*
  FROM ops.shipping_records sr
  WHERE sr.lot_id = pr.lot_id
    AND (pr.production_date IS NULL OR (sr.ship_date IS NOT NULL AND sr.ship_date BETWEEN pr.production_date AND (pr.production_date + INTERVAL '21 days')))
  ORDER BY
    CASE WHEN pr.production_date IS NULL OR sr.ship_date IS NULL THEN 999999 ELSE (sr.ship_date - pr.production_date) END ASC,
    sr.shipping_record_id ASC
  LIMIT 1
) sr ON TRUE
WHERE pr.production_date IS NOT NULL
ON CONFLICT (lot_id, record_date) DO UPDATE SET
  production_record_id = EXCLUDED.production_record_id,
  production_line = EXCLUDED.production_line,
  part_number = EXCLUDED.part_number,
  units_planned = EXCLUDED.units_planned,
  units_actual = EXCLUDED.units_actual,
  downtime_minutes = EXCLUDED.downtime_minutes,
  line_issue_flag = EXCLUDED.line_issue_flag,
  primary_issue = EXCLUDED.primary_issue,
  inspection_record_id = EXCLUDED.inspection_record_id,
  total_defects = EXCLUDED.total_defects,
  top_defect_code = EXCLUDED.top_defect_code,
  shipping_record_id = EXCLUDED.shipping_record_id,
  ship_status = EXCLUDED.ship_status,
  ship_date = EXCLUDED.ship_date,
  qty_shipped = EXCLUDED.qty_shipped,
  reconciliation_status = EXCLUDED.reconciliation_status,
  missing_inspection = EXCLUDED.missing_inspection,
  missing_shipping = EXCLUDED.missing_shipping,
  incomplete_reason = EXCLUDED.incomplete_reason,
  updated_at = NOW();

COMMIT;